{{Documentation subpage}} <!-- Please place categories where indicated at the bottom of this page and interwikis at Wikidata (see [[Wikipedia:Wikidata]]) --> {{High-use}} {{Lua|Module:Infobox|Module:InfoboxImage|Module:Check for unknown parameters}}
{{tlx|Infobox event}} should be used to specify one-off events, usually at the top of an article. For recurring events, use {{nowrap|{{tlx|Infobox recurring event}}}}. For other type of events, check: [[Wikipedia:List of infoboxes]]
== Usage == {{Parameter names example | title | partof | logo | logo_size | logo_upright | logo_alt | logo_caption | image | image_size | image_upright | image_alt | caption | native_name | native_name_lang | english_name | time | timezone | duration | date | venue | location | coordinates | also_known_as | type | theme | cause | motive | target | perpetrator | first_reporter | budget | patron | organisers | filmed_by | participants | outcome | casualties1 | casualties2 | casualties3 | reported deaths | reported injuries | reported missing | reported property damage | burial | displaced | inquiries | inquest | coroner | arrests | suspects | accused | convicted | charges | trial | verdict | convictions | sentence | publication_bans | litigation | awards | url | blank_label | blank1_label | blank2_label | website | notes }}
<syntaxhighlight lang="wikitext" style="overflow:auto;"> {{Infobox event | title = <!-- Title to display, if other than page name --> | image = | image_upright = | image_alt = | caption = | native_name = | native_name_lang = | english_name = | time = | timezone = | duration = <!-- {{duration|h=x|m=x|s=x}} or {{time interval|date1|date2|options}} --> | date = <!-- {{start date|YYYY|MM|DD}} or {{start and end dates|YYYY|MM|DD|YYYY|MM|DD}} --> | venue = | location = | coordinates = <!-- {{coord|LAT|LON|region:XXXX_type:event|display=inline,title}} --> | also_known_as = | type = | theme = | cause = | motive = | target = | perpetrator = | first_reporter = | budget = | patron = <!-- or |patrons= --> | organisers = <!-- or |organizers= --> | filmed_by = | participants = | outcome = | casualties1 = | casualties2 = | casualties3 = | reported deaths = | reported injuries = | reported missing = | reported property damage = | burial = | displaced = | inquiries = | inquest = | coroner = | arrests = | suspects = | accused = | convicted = | charges = | trial = | verdict = | convictions = | sentence = | publication_bans = | litigation = | awards = | url = | blank_label = <!-- or |blank_data= --> | blank1_label = <!-- or |blank1_data= --> | blank2_label = <!-- or |blank2_data= --> | website = <!-- {{URL|example.com}} --> | notes = }} </syntaxhighlight> {{clear}}
=== Parameters === {{TemplateData header}} <templatedata> { "params": { "nongregorian": {}, "partof": { "label": "Part of" }, "child": { "label": "Child infobox", "description": "Set to \"yes\" if you are embedding this infobox in another one", "type": "string" }, "title": { "aliases": [ "event", "name", "Event_Name" ], "label": "Title", "description": "Name of the event, if omitted, the page name will be used", "type": "line" }, "logo": { "label": "Logo", "description": "Logo filename", "type": "wiki-file-name" }, "logo_size": { "label": "Logo size" }, "logo_upright": { "label": "Logo upright (scale factor)" }, "logo_alt": { "label": "Logo alt text", "description": "A description of the logo intended for the blind; say what you see. No formatting.", "example": "Black text reading \"example\" on white circle.", "type": "string" }, "logo_caption": { "label": "Logo caption", "description": "Caption to display under the logo.", "type": "line" }, "image": { "aliases": [ "image_name", "Image_Name" ], "label": "Image", "description": "Name of the image of the event", "type": "wiki-file-name", "suggested": true }, "image_size": { "aliases": [ "Imagesize" ], "label": "Image size", "description": "Image size in pixels", "deprecated": "Use image_upright instead." }, "image_upright": { "label": "Image upright (scale factor)", "description": "Image scaling factor; defaults to 1 if left empty – see [[WP:IMGSIZE]]" }, "thumbtime": { "aliases": [ "Thumb_Time" ], "label": "Thumbnail time", "description": "If the image parameter is a video, this timestamp is the section of the video that will be used as a thumbnail." }, "image_alt": { "aliases": [ "alt", "Image_Alt" ], "label": "Image alt text", "description": "A description of the logo intended for the blind; say what you see. No formatting.", "type": "string" }, "caption": { "aliases": [ "Image_Caption" ], "label": "Image caption", "description": "Optional caption of the image", "type": "line" }, "map": {}, "map_size": {}, "map_alt": {}, "map_caption": {}, "native_name": { "label": "Native name", "description": "The native name of the event, if different" }, "native_name_lang": { "label": "Language of native name", "description": "ISO 639-2 code for the native name e.g. 'fr' for French", "type": "string" }, "English_name": {}, "date": { "description": "{{start date|YYYY|MM|DD}} for the date of a single-day event or {{start and end dates|YYYY|MM|DD|YYYY|MM|DD}} for multi-day events" }, "duration": { "label": "Duration of the event" }, "venue": { "label": "Venue", "description": "name of the particular venue (alternative to location)" }, "Location": { "aliases": [ "location", "place" ], "label": "Location", "description": "The location of the event", "type": "line" }, "coordinates": { "label": "Coordinates", "description": "Use {{Coord}}, with display=inline,title", "example": "{{coord|LAT|LON|region:XXXX_type:event|display=inline,title}}" }, "also known as": { "aliases": [ "also_known_as", "AKA", "aka" ], "label": "Also known as", "type": "line" }, "type": {}, "theme": {}, "cause": {}, "motive": {}, "perpetrator": { "label": "Perpetrator", "type": "line", "description": "The perpetrator of the event, if it was a crime" }, "reporter": { "aliases": [ "first reporter" ], "label": "Reporter", "type": "line", "description": "First or key reporter(s)" }, "budget": { "label": "Budget", "description": "The larger of budgeted income or expense", "type": "line" }, "patron": { "aliases": [ "patrons" ], "label": "Patrons", "type": "line" }, "organizers": { "aliases": [ "organisers" ], "label": "Organizers" }, "filmed by": {}, "participants": { "label": "Participants", "description": "The typical number of participants", "type": "line" }, "outcome": { "aliases": [ "result" ], "label": "Outcome", "type": "line" }, "casualties1": { "label": "First group of or total casualties", "description": "Use to indicate the first casualties of an event, or for the total casualties if there is only one group of casualties. Include a short explanation of that group if it is the first casualties. ", "example": "150 (initial collapse of mine)" }, "casualties2": { "label": "Second group of casualties", "description": "Use to indicate the second group of casualties of an event. Include a short explanation of the group. ", "example": "8 (death from injuries while awaiting rescue)", "type": "string" }, "casualties3": { "label": "Third group of casualties", "description": "Use to indicate the third group of casualties of an event. Include a short explanation of the group. ", "example": "2 (in hospital following rescue)", "type": "string" }, "reported deaths": { "aliases": [ "reported death(s)", "Deaths", "fatalities" ] }, "reported injuries": { "aliases": [ "injuries" ], "label": "Injuries", "type": "line" }, "missing": { "aliases": [ "reported missing" ], "label": "Missing", "description": "The number of people missing", "type": "string" }, "property damage": { "aliases": [ "reported property damage" ], "label": "Property damage", "type": "line" }, "burial": {}, "displaced": { "label": "Displaced", "description": "People forced to leave home", "type": "line" }, "inquiries": {}, "inquest": {}, "coroner": {}, "arrests": {}, "suspects": { "aliases": [ "susperps" ] }, "accused": {}, "convicted": {}, "charges": {}, "trial": {}, "verdict": {}, "convictions": {}, "sentence": {}, "publication bans": { "aliases": [ "publication_bans" ], "label": "Publication bans", "type": "line" }, "litigation": {}, "awards": {}, "footage": { "aliases": [ "url" ], "label": "Footage of the event", "description": "The name and/or url of footage of the event." }, "blank_label": { "label": "First blank label", "description": "Use with First blank data parameter" }, "blank_data": { "label": "First blank data", "description": "Use with First blank label parameter" }, "blank1_label": { "label": "Second blank label", "description": "Use with Second blank data parameter" }, "blank1_data": { "label": "Second blank data", "description": "Use with Second blank label parameter" }, "blank2_label": { "label": "Third blank label", "description": "Use with Third blank data parameter" }, "blank2_data": { "label": "Third blank data", "description": "Use with Third blank label parameter" }, "website": { "aliases": [ "URL" ], "label": "Website", "description": "Use {{URL}}", "example": "{{URL|example.com}}" }, "module": { "label": "Module", "description": "For embedding another infobox as a child", "example": "{{infobox person|child=yes}}", "type": "string" }, "notes": { "label": "Notes", "description": "Free-form notes for the bottom of the infobox", "type": "content" }, "Target": { "label": "Target of the event", "type": "string" }, "timezone": { "label": "Timezone", "description": "If Time is specified, the timezone of the event. Brackets/parentheses will be added automatically. ", "example": "[[AWST]]", "type": "string", "aliases": [ "Timezone" ] }, "time": { "label": "Time of the event", "description": "Time that the event occurred, in the relevant timezone. Use the Timezone parameter to display the timezone.", "aliases": [ "Time" ] } }, "description": "{{Infobox event}} should be used to specify one-off events, usually at the top of an article. For recurring events, use {{Infobox recurring event}}. For other type of events, check: [[Wikipedia:List of infoboxes]]", "paramOrder": [ "title", "partof", "logo", "logo_size", "logo_upright", "logo_alt", "logo_caption", "image", "image_size", "image_upright", "image_alt", "caption", "thumbtime", "native_name", "English_name", "nongregorian", "map", "map_size", "map_alt", "map_caption", "native_name_lang", "date", "time", "timezone", "duration", "venue", "Location", "coordinates", "also known as", "type", "theme", "cause", "motive", "Target", "perpetrator", "reporter", "budget", "patron", "organizers", "filmed by", "participants", "outcome", "casualties1", "casualties2", "casualties3", "reported deaths", "reported injuries", "missing", "property damage", "burial", "displaced", "inquiries", "inquest", "coroner", "arrests", "suspects", "accused", "convicted", "charges", "trial", "verdict", "convictions", "sentence", "publication bans", "litigation", "awards", "footage", "blank_label", "blank_data", "blank1_label", "blank1_data", "blank2_label", "blank2_data", "website", "child", "module", "notes" ], "format": "block" } </templatedata>
== Example == {{Infobox event | title = Bombay explosion | image = Bombay-Docks-aftermath1.png | caption = Smoke billowing out of the harbour | date = 14 April 1944 | time = 16:15 IST (10:45 UTC) | place = Victoria Dock, Bombay, [[British Raj|British India]] | coordinates = {{coord|18.9527772|N|72.8449774|E|type:event_region:IN|display=inline,title}} | cause = ship fire | url = {{URL|example.com}} | casualties1 = 800+ dead | casualties2 = 3,000 injured | website = {{URL|example.com}} }} <syntaxhighlight lang="wikitext" style="overflow:auto;"> {{Infobox event | title = Bombay explosion | image = Bombay-Docks-aftermath1.png | caption = Smoke billowing out of the harbour | date = 14 April 1944 | time = 16:15 IST (10:45 UTC) | place = Victoria Dock, Bombay, [[British Raj|British India]] | coordinates = {{coord|18.9527772|N|72.8449774|E|type:event_region:IN|display=inline,title}} | cause = ship fire | url = {{URL|example.com}} | casualties1 = 800+ dead | casualties2 = 3,000 injured | website = {{URL|example.com}} }} </syntaxhighlight> {{clear}}
